class BookMyShow:

    def __init__(self, n: int, m: int):
        self.n = n
        self.m = m
        self.seats = [0] * n  # seats[r] = number of seats already taken in row r
        self.min_tree = [0] * (4 * n)
        self.sum_tree = [0] * (4 * n)
        self.build(0, 0, n - 1)

    def build(self, node, l, r):
        if l == r:
            self.min_tree[node] = 0
            self.sum_tree[node] = 0
            return
        mid = (l + r) // 2
        self.build(2 * node + 1, l, mid)
        self.build(2 * node + 2, mid + 1, r)
        self.min_tree[node] = min(self.min_tree[2 * node + 1], self.min_tree[2 * node + 2])
        self.sum_tree[node] = self.sum_tree[2 * node + 1] + self.sum_tree[2 * node + 2]

    def update(self, node, l, r, idx, val):
        if l == r:
            self.min_tree[node] = val
            self.sum_tree[node] = val
            return
        mid = (l + r) // 2
        if idx <= mid:
            self.update(2 * node + 1, l, mid, idx, val)
        else:
            self.update(2 * node + 2, mid + 1, r, idx, val)
        self.min_tree[node] = min(self.min_tree[2 * node + 1], self.min_tree[2 * node + 2])
        self.sum_tree[node] = self.sum_tree[2 * node + 1] + self.sum_tree[2 * node + 2]

    def query_min(self, node, l, r, ql, qr):
        if qr < l or ql > r:
            return float('inf')
        if ql <= l and r <= qr:
            return self.min_tree[node]
        mid = (l + r) // 2
        left = self.query_min(2 * node + 1, l, mid, ql, qr)
        right = self.query_min(2 * node + 2, mid + 1, r, ql, qr)
        return min(left, right)

    def query_sum(self, node, l, r, ql, qr):
        if qr < l or ql > r:
            return 0
        if ql <= l and r <= qr:
            return self.sum_tree[node]
        mid = (l + r) // 2
        left = self.query_sum(2 * node + 1, l, mid, ql, qr)
        right = self.query_sum(2 * node + 2, mid + 1, r, ql, qr)
        return left + right

    def find_first_row(self, node, l, r, ql, qr, k):
        if self.min_tree[node] > self.m - k:
            return -1
        if l == r:
            return l
        mid = (l + r) // 2
        left = -1
        if ql <= mid:
            left = self.find_first_row(2 * node + 1, l, mid, ql, min(qr, mid), k)
        if left != -1:
            return left
        if qr > mid:
            return self.find_first_row(2 * node + 2, mid + 1, r, max(ql, mid + 1), qr, k)
        return -1

    def gather(self, k: int, maxRow: int) -> list[int]:
        if k > self.m:
            return []
        row = self.find_first_row(0, 0, self.n - 1, 0, maxRow, k)
        if row == -1:
            return []
        c = self.seats[row]
        self.seats[row] += k
        self.update(0, 0, self.n - 1, row, self.seats[row])
        return [row, c]

    def scatter(self, k: int, maxRow: int) -> bool:
        total_seats = (maxRow + 1) * self.m
        taken = self.query_sum(0, 0, self.n - 1, 0, maxRow)
        if total_seats - taken < k:
            return False
        remaining = k
        for r in range(maxRow + 1):
            available = self.m - self.seats[r]
            if available == 0:
                continue
            take = min(available, remaining)
            self.seats[r] += take
            self.update(0, 0, self.n - 1, r, self.seats[r])
            remaining -= take
            if remaining == 0:
                break
        return True
```

